        if l not in name_lens:
            name_lens[l] = []
        name_lens[l].append(name)

print("\nName length distribution:")
for l in sorted(name_lens.keys()):
    print(f"  Length {l}: {len(name_lens[l])} names, examples: {name_lens[l][:3]}")

# Check for name duplicates (by original name)
from collections import Counter
name_counts = Counter()
for row in range(3, ws1.max_row + 1):
    name = ws1.cell(row, 5).value
    if name:
        name_counts[name] += 1
name_dups = {k:v for k,v in name_counts.items() if v > 1}
print(f"\nDuplicate names: {len(name_dups)}")
for n, c in list(name_dups.items())[:20]:
    print(f"  {n}: {c} times")

# Check student ID lengths
sid_lens = Counter()
for row in range(3, ws1.max_row + 1):
    sid = str(ws1.cell(row, 4).value or '')
    sid_lens[len(sid)] += 1
print(f"\nStudent ID length distribution: {dict(sid_lens)}")

# Sample short IDs
for row in range(3, ws1.max_row + 1):
